/**
 * A trade in a CDS tranche.
 * <p>
 * An Over-The-Counter (OTC) trade in a {@link CdsTranche}.
 * <p>
 * A CDS tranche represents a slice of a CDS index portfolio, defined by attachment
 * and detachment points that determine the subordination level.
 */
@BeanDefinition
public final class CdsTrancheTrade
    implements ProductTrade, ResolvableTrade<ResolvedCdsTrancheT rade>, ImmutableBean, Serializable {

  /**
   * The additional trade information, defaulted to an empty instance.
   * <p>
   * This allows additional information to be attached to the trade.
   */
  @PropertyDefinition(validate = "notNull", overrideGet = true)
  private final TradeInfo info;
  /**
   * The CDS tranche product that was agreed when the trade occurred.
   * <p>
   * The product captures the contracted financial details of the trade.
   */
  @PropertyDefinition(validate = "notNull", overrideGet = true)
  private final CdsTranche product;
  /**
   * The upfront fee of the product.
   * <p>
   * This specifies a single amount payable by the buyer to the seller.
   * Thus the sign must be compatible with the product Pay/Receive flag.
   * <p>
   * Some CDS tranches, especially legacy products, are traded at par and the upfront fee is not paid.
   */
  @PropertyDefinition(get = "optional")
  private final AdjustablePayment upfrontFee;

  //-------------------------------------------------------------------------
  @Override
  public CdsTrancheTrade withInfo(PortfolioItemInfo info) {
    return new CdsTrancheTrade(TradeInfo.from(info), product, upfrontFee);
  }

  //-------------------------------------------------------------------------
  @Override
  public PortfolioItemSummary summarize() {
    // 2Y Buy USD 1mm TRANCHE(3-7%) / 1.5% : 21Jan18-21Jan20
    CdsTranche trancheProduct = product;
    CdsIndex index = trancheProduct.getUnderlyingIndex();
    StringBuilder buf = new StringBuilder(96);
    buf.append(SummarizerUtils.datePeriod(index.getPaymentSchedule().getStartDate(), index.getPaymentSchedule().getEndDate()));
    buf.append(' ');
    buf.append(index.getBuySell());
    buf.append(' ');
    buf.append(SummarizerUtils.amount(index.getCurrency(), index.getNotional()));
    buf.append(" TRANCHE(");
    buf.append(SummarizerUtils.percent(trancheProduct.getAttachmentPoint()));
    buf.append("-");
    buf.append(SummarizerUtils.percent(trancheProduct.getDetachmentPoint()));
    buf.append(") / ");
    buf.append(SummarizerUtils.percent(index.getFixedRate()));
    buf.append(" : ");
    buf.append(SummarizerUtils.dateRange(index.getPaymentSchedule().getStartDate(), index.getPaymentSchedule().getEndDate()));
    return SummarizerUtils.summary(this, ProductType.of("CdsTranche", "CDS Tranche"), buf.toString(), index.getCurrency());
  }

  @Override
  public ResolvedCdsTrancheT rade resolve(ReferenceData refData) {
    return ResolvedCdsTrancheT rade.builder()
        .info(info)
        .product(product.resolve(refData))
        .upfrontFee(upfrontFee != null ? upfrontFee.resolve(refData) : null)
        .build();
  }

